351	/* Set a field in a record. field_name_idx and val_idx are value indices.
352	 * Returns 0 on success, -1 on error. */
353	int val_rec_set(int rec_idx, int field_name_idx, int val_idx) {
354	    if (rec_idx < 0 || rec_idx >= val_count) return -1;
355	    if (val_type[rec_idx] != VAL_REC) return -1;
356	
357	    /* Check if field already exists — update in place */
358	    int fc = val_rec_count[rec_idx];
359	    int i = 0;
360	    while (i < fc) {
361	        if (val_rec_fld[vrf(rec_idx, i)] == field_name_idx) {
362	            val_rec_val[vrf(rec_idx, i)] = val_idx;
363	            return 0;
364	        }
365	        i = i + 1;
366	    }
367	
368	    /* Add new field */
369	    if (fc >= MAX_FIELDS) return -1;
370	    val_rec_fld[vrf(rec_idx, fc)] = field_name_idx;
371	    val_rec_val[vrf(rec_idx, fc)] = val_idx;
372	    val_rec_count[rec_idx] = fc + 1;
373	    return 0;
374	}
