376	/* Get a field value from a record by field name string.
377	 * Returns value index, or -1 if not found. */
378	int val_rec_get(int rec_idx, char *field_name) {
379	    if (rec_idx < 0 || rec_idx >= val_count) return -1;
380	    if (val_type[rec_idx] != VAL_REC) return -1;
381	
382	    int fc = val_rec_count[rec_idx];
383	    int i = 0;
384	    while (i < fc) {
385	        int fn_idx = val_rec_fld[vrf(rec_idx, i)];
386	        if (val_type[fn_idx] == VAL_STR && str_eq(val_str_ptr(fn_idx), field_name)) {
387	            return val_rec_val[vrf(rec_idx, i)];
388	        }
389	        i = i + 1;
