                char tmp[MAX_VAR_VAL];
                val_to_str(fvi, tmp);
                int k = 0;
                while (tmp[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
                    expand_pool[expand_pool_used] = tmp[k];
                    expand_pool_used = expand_pool_used + 1;
                    k = k + 1;
