1190	int eval_block(char *block) {
1191	    int blen = str_len(block);
1192	    if (blen < 2 || block[0] != 123 || block[blen - 1] != 125) {
1193	        uart_puts("error: invalid block");
1194	        uart_newline();
1195	        return RET_ERR;
1196	    }
1197	
1198	    /* Push block content onto block stack so it survives recursive calls */
1199	    int save = block_stack_top;
1200	    int bi = block_push(block);
1201	    char *blk = block_get(bi);
1202	    int i = 1; /* skip '{' */
1203	    int end = blen - 1; /* before '}' */
1204	
1205	    while (i < end) {
1206	        /* Skip whitespace and newlines */
1207	        while (i < end && (blk[i] == 32 || blk[i] == 9 || blk[i] == 10))
1208	            i = i + 1;
1209	        if (i >= end) break;
1210	
1211	        /* Collect one line into global buffer, respecting brace nesting */
1212	        int li = 0;
1213	        int depth = 0;
1214	        while (i < end && li < MAX_LINE_LEN - 1) {
1215	            if (blk[i] == 123) depth = depth + 1;
1216	            if (blk[i] == 125) depth = depth - 1;
1217	            if ((blk[i] == 10 || blk[i] == 59) && depth == 0) {
1218	                i = i + 1;
1219	                break;
1220	            }
1221	            eval_line_buf[li] = blk[i];
1222	            li = li + 1;
1223	            i = i + 1;
1224	        }
1225	        eval_line_buf[li] = 0;
1226	        if (li == 0) continue;
1227	
1228	        int ret = eval_line(eval_line_buf);
1229	        if (ret == RET_BREAK || ret == RET_CONTINUE || ret == RET_ERR) {
1230	            block_pop(save);
1231	            return ret;
1232	        }
1233	        if (exit_flag) { block_pop(save); return RET_OK; }
1234	    }
1235	    block_pop(save);
1236	    return RET_OK;
1237	}
