int cmd_incr() {
    if (expand_count < 2) {
        uart_puts("error: incr: expected variable name");
        uart_newline();
        return RET_ERR;
    }
    char *name = exp_str(1);
    int amount = 1;
    if (expand_count >= 3) {
        amount = str_to_int(exp_str(2));
    }
    int vi = env_get(name);
    if (vi < 0) {
        uart_puts("error: incr: undefined variable: ");
        uart_puts(name);
        uart_newline();
        return RET_ERR;
    }
    if (val_type[vi] != VAL_INT) {
        uart_puts("error: incr: not an integer: ");
        uart_puts(name);
        uart_newline();
        return RET_ERR;
    }
    val_int[vi] = val_int[vi] + amount;
    last_result = vi;
    return RET_OK;
}

